    XPT2046_DCLK=0;
    XPT2046_CS=0;
    for(i=0;i&lt;8;i++)
    {
        XPT2046_DIN=Command&amp;(0x80&gt;&gt;i);
        XPT2046_DCLK=1;
        XPT2046_DCLK=0;
    }
    for(i=0;i&lt;16;i++)
    {
        XPT2046_DCLK=1;
        XPT2046_DCLK=0;
        if(XPT2046_DOUT){Data|=(0x8000&gt;&gt;i);}
    }
    XPT2046_CS=1;

    return Data&gt;&gt;8;
}
